        <div className="flex items-center gap-3 mb-4">
          <div className="w-9 h-9 rounded-xl flex items-center justify-center" style={{ background:'rgba(42,157,143,0.12)', color:'#2a9d8f' }}>
            <Server size={16}/>
          </div>
          <div>
            <p className="font-semibold text-[.95rem]" style={{ color: ink }}>Examor</p>
            <p className="text-[.65rem] font-mono" style={{ color:'#2a9d8f' }}>React · Node.js · SQL Server · JWT</p>
          </div>
          <span className="ml-auto text-[.58rem] font-semibold px-2 py-0.5 rounded-full" style={{ background:'rgba(240,165,0,0.12)', color:'#e8920a', border:'1px solid rgba(240,165,0,0.25)' }}>
            🔄 In Progress
