function GlassCard({ p, m, chips, index, isExamor, dark, onExamorClick }) {
  const [hov, setHov] = useState(false);
  const [pos, setPos] = useState({ x:50, y:50 });

  const glass = dark ? 'rgba(255,255,255,0.04)' : 'rgba(255,255,255,0.60)';
  const bord  = dark ? 'rgba(255,255,255,0.09)' : 'rgba(255,255,255,0.80)';
  const ink   = dark ? '#f0f0f8' : '#1a1a2e';
  const muted = dark ? 'rgba(255,255,255,0.5)' : '#5a5a72';
  const chip  = dark ? 'rgba(255,255,255,0.06)' : 'rgba(255,255,255,0.65)';

  const delay = [0, 0.08, 0.14, 0.20, 0.26, 0.32][index] || 0;

  return (
    <div
      className="reveal relative rounded-2xl overflow-hidden flex flex-col"
      style={{
        transitionDelay: `${delay}s`,
        background: glass,
        border: `1px solid ${hov ? m.accent + '44' : bord}`,
        backdropFilter: 'blur(22px) saturate(160%)',
        WebkitBackdropFilter: 'blur(22px) saturate(160%)',
        boxShadow: hov ? `0 20px 55px ${m.glow}, inset 0 1px 0 rgba(255,255,255,${dark?'0.08':'0.90'})` : `0 3px 20px rgba(0,0,0,${dark?'0.2':'0.06'}), inset 0 1px 0 rgba(255,255,255,${dark?'0.06':'0.85'})`,
        transform: hov ? 'translateY(-6px) scale(1.005)' : 'none',
        transition: 'all 0.32s cubic-bezier(0.22,1,0.36,1)',
        cursor: isExamor ? 'pointer' : 'default',
      }}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      onMouseMove={e => { const r=e.currentTarget.getBoundingClientRect(); setPos({ x:((e.clientX-r.left)/r.width*100).toFixed(1), y:((e.clientY-r.top)/r.height*100).toFixed(1) }); }}
      onClick={isExamor ? onExamorClick : undefined}>

      {/* Mouse glow */}
      <div className="absolute inset-0 pointer-events-none rounded-2xl transition-opacity duration-300"
        style={{ opacity: hov ? 1 : 0, background: `radial-gradient(circle at ${pos.x}% ${pos.y}%, ${m.glow}, transparent 60%)` }} />

      {/* Specular top line */}
      <div className="absolute top-0 left-5 right-5 h-px pointer-events-none"
        style={{ background: `linear-gradient(90deg,transparent,${dark?'rgba(255,255,255,0.15)':'rgba(255,255,255,0.9)'},transparent)` }} />

      <div className="relative z-10 p-8 flex flex-col h-full">
        <div className="flex items-start justify-between mb-5">
          <div className="flex items-center gap-2.5">
            <div className="w-10 h-10 rounded-xl flex items-center justify-center"
              style={{ background:`${m.accent}18`, border:`1px solid ${m.accent}30`, color:m.accent }}>
              <m.Icon size={18}/>
            </div>
            <span className="text-[.65rem] font-semibold tracking-wider uppercase px-2.5 py-1 rounded-full border"
              style={{ background:`${m.accent}12`, borderColor:`${m.accent}28`, color:m.accent }}>
              {p.tag}
            </span>
          </div>
          {isExamor && (
            <span className="text-[.58rem] font-semibold px-2 py-0.5 rounded-full"
              style={{ background:'rgba(42,157,143,0.12)', color:'#2a9d8f', border:'1px solid rgba(42,157,143,0.25)' }}>
              🔄 In Progress
            </span>
          )}
        </div>

        <h3 className="font-serif-display text-xl tracking-tight leading-snug mb-2" style={{ color: ink }}>{p.title}</h3>
        <p className="text-[.87rem] leading-[1.75] flex-1" style={{ color: muted }}>{p.desc}</p>

        {isExamor && (
          <div className="flex gap-1.5 flex-wrap mt-3">
            {['React','Node.js','SQL Server','JWT','Express'].map(tech => (
              <span key={tech} className="text-[.62rem] font-mono px-2 py-0.5 rounded-full border"
                style={{ background:`${m.accent}10`, borderColor:`${m.accent}28`, color:m.accent }}>
                {tech}
              </span>
            ))}
          </div>
        )}

        <div className="flex items-center justify-between mt-5 pt-4"
          style={{ borderTop:`1px solid ${dark?'rgba(255,255,255,0.07)':'rgba(26,26,46,0.07)'}` }}>
          <div className="flex gap-1.5 flex-wrap">
            {chips.map(c => (
              <span key={c} className="text-[.67rem] font-medium px-2 py-0.5 rounded"
                style={{ background:chip, border:`1px solid ${dark?'rgba(255,255,255,0.08)':'rgba(26,26,46,0.07)'}`, color:muted }}>
                {c}
              </span>
            ))}
          </div>
          <div className="w-7 h-7 rounded-lg flex items-center justify-center transition-all duration-200"
            style={{ background: hov ? `${m.accent}18` : chip, border:`1px solid ${hov ? m.accent+'38' : dark?'rgba(255,255,255,0.08)':'rgba(26,26,46,0.07)'}`, color: hov ? m.accent : muted }}>
            <ArrowUpRight size={13}/>
          </div>
        </div>
      </div>
    </div>
  );
}

